:root {
  --bg-card: #ffffff;
  --bg-header: #1e3a2f;
  --bg-plant-healthy: #f0faf3;
  --bg-plant-warning: #fffbf0;
  --bg-plant-urgent: #fff5f5;
  --border-healthy: #a8d8b0;
  --border-warning: #f5d87e;
  --border-urgent: #f5a8a8;
  --color-title: #ffffff;
  --color-subtitle: #a8c9b5;
  --color-plant-name: #1e3a2f;
  --color-plant-type: #7a9e8a;
  --color-water-text-healthy: #3a8a55;
  --color-water-text-warning: #b07c10;
  --color-water-text-urgent: #c0392b;
  --color-task-text: #4a6a55;
  --color-task-date: #9ab5a5;
  --streak-bg: #2e5c42;
  --streak-number-color: #7eeaa0;
  --streak-label-color: #a8c9b5;
  --dot-healthy: #3cb371;
  --dot-warning: #f0c040;
  --dot-urgent: #e05050;
  --bar-bg: #e0ece5;
  --bar-high: #3cb371;
  --bar-medium: #6abf85;
  --bar-low: #f0c040;
  --bar-critical: #e05050;
  --task-done-color: #3cb371;
  --task-pending-color: #f0c040;
  --footer-border: #dceee3;
}

.tracker {
  background: var(--bg-card);
  border-radius: 16px;
  overflow: hidden;
  width: 520px;
  max-width: 100%;
}

.tracker-header {
  background: var(--bg-header);
  padding: 14px 18px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.header-left {
  display: flex;
  align-items: center;
  gap: 12px;
}

.leaf-icon {
  font-size: 28px;
  line-height: 1;
}

.tracker-title {
  margin: 0;
  font-size: 18px;
  font-weight: 700;
  color: var(--color-title);
  line-height: 1.2;
}

.tracker-subtitle {
  margin: 0;
  font-size: 12px;
  color: var(--color-subtitle);
  line-height: 1.4;
}

.streak-badge {
  background: var(--streak-bg);
  border-radius: 10px;
  padding: 6px 14px;
  display: flex;
  flex-direction: column;
  align-items: center;
}

.streak-number {
  font-size: 22px;
  font-weight: 800;
  color: var(--streak-number-color);
  line-height: 1;
}

.streak-label {
  font-size: 10px;
  color: var(--streak-label-color);
  line-height: 1.4;
}

.plants-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 10px;
  padding: 14px 16px;
}

.plant-card {
  border-radius: 12px;
  border: 1.5px solid transparent;
  padding: 10px 10px 10px 10px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.plant-healthy {
  background: var(--bg-plant-healthy);
  border-color: var(--border-healthy);
}

.plant-warning {
  background: var(--bg-plant-warning);
  border-color: var(--border-warning);
}

.plant-urgent {
  background: var(--bg-plant-urgent);
  border-color: var(--border-urgent);
}

.plant-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 4px;
}

.plant-emoji {
  font-size: 24px;
  line-height: 1;
}

.status-dot {
  width: 9px;
  height: 9px;
  border-radius: 50%;
  display: inline-block;
}

.dot-healthy { background: var(--dot-healthy); }
.dot-warning { background: var(--dot-warning); }
.dot-urgent  { background: var(--dot-urgent); }

.plant-name {
  margin: 0;
  font-size: 13px;
  font-weight: 700;
  color: var(--color-plant-name);
  line-height: 1.2;
}

.plant-type {
  margin: 0;
  font-size: 10px;
  color: var(--color-plant-type);
  line-height: 1.3;
}

.care-bar-wrap {
  background: var(--bar-bg);
  border-radius: 4px;
  height: 5px;
  width: 100%;
  margin-top: 6px;
  overflow: hidden;
}

.care-bar {
  height: 100%;
  border-radius: 4px;
}

.bar-high      { width: 80%; background: var(--bar-high); }
.bar-medium    { width: 55%; background: var(--bar-medium); }
.bar-low       { width: 30%; background: var(--bar-low); }
.bar-critical  { width: 10%; background: var(--bar-critical); }

.next-water {
  margin: 4px 0 0;
  font-size: 10px;
  font-weight: 600;
  line-height: 1.3;
}

.plant-healthy .next-water { color: var(--color-water-text-healthy); }
.plant-warning .next-water { color: var(--color-water-text-warning); }
.plant-urgent  .next-water { color: var(--color-water-text-urgent); }

.tracker-footer {
  border-top: 1.5px solid var(--footer-border);
  padding: 10px 18px 14px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.task-item {
  display: flex;
  align-items: center;
  gap: 8px;
}

.task-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}

.task-done    { background: var(--task-done-color); }
.task-pending { background: var(--task-pending-color); }

.task-text {
  font-size: 12px;
  color: var(--color-task-text);
  font-weight: 500;
  flex: 1;
}

.task-date {
  font-size: 11px;
  color: var(--color-task-date);
}
